+
+    // ReduceScope case
+    let gate_reduce = GatePacket {
+        lambda: 100,
+        lambda_prev: 95,
+        boundary_edges: 30, // Triggers boundary spike
+        boundary_concentration_q15: 8192,
+        partition_count: 3,
+        flags: 0,
