+fn bench_tier0_inference(c: &mut Criterion) {
+    let mut group = c.benchmark_group("tier0_inference");
+
+    for seq_len in [16, 32, 64].iter() {
+        let mut config = TransformerConfig::baseline();
+        config.seq_len_max = *seq_len;
