+    println!("  Softmax scale: {:.4}\n", config.softmax_scale);
+
+    // Example 1: Single-head attention
+    {
+        println!("Example 1: Single-head attention (128 tokens, 64 dims)");
+
+        let seq_len = 128;
+        let head_dim = 64;
+
+        // Create random-like input (deterministic for demo)
