+        state.update(&scores2, &values2, head_dim);
+
+        state.finalize();
+
+        // Verify output is normalized (sum should be reasonable)
+        let sum: f32 = state.output.iter().sum();
+        assert!(sum > 0.0 && sum < 10.0, "Output sum is {}", sum);
+    }
+}

